{"operationName":"quickSearch","variables":{"quickSearch":"statusgator.com","rpp":5,"analytics":{"suggestionsExist":false,"source":"SmartDash","savedSearchesExist":false,"orgId":"0017y00001pTixVAAS","companyName":"Dane.Insure"},"usePredictIntent":false,"useReactGpiSearch":true,"skipRedis":true,"searchUUID":"683c5b8a-e5d8-4afc-9465-76763ad9be6b"},"query":"query quickSearch($rpp: Float!, $quickSearch: String, $analytics: QuickSeachAnalyticshArgs, $usePredictIntent: Boolean, $useReactGpiSearch: Boolean, $searchUUID: String, $skipRedis: Boolean) {
  quickSearch(
    rpp: $rpp
    quickSearch: $quickSearch
    analytics: $analytics
    usePredictIntent: $usePredictIntent
    useReactGpiSearch: $useReactGpiSearch
    searchUUID: $searchUUID
    skipRedis: $skipRedis
  ) {
    companies {
      companiesCount
      data {
        companyDomain
        companyEmployeeRange
        companyID
        companyName
        industries {
          code
          displayName
          score
        }
        isDefunct
        location {
          City
          CountryCode
          State
          Street
          Zip
        }
        logo
        socialNetworkUrls {
          socialNetworkType
          socialNetworkUrl
        }
        ultimateParent {
          id
        }
      }
      maxResults
      totalResults
    }
    contacts {
      companiesCount
      data {
        companyId
        companyName
        isDefunct
        logo
        profileImageURL
        name
        personID
        title
        ultimateParent {
          id
        }
      }
      maxResults
      totalResults
    }
    onEnterTops {
      type
      value
    }
    tops {
      topCount
      topName
      topValue
      type
      value
    }
    trySearchSuggestions {
      items {
        displayItem
        searchType
        suggestions {
          type
          value
        }
      }
      showAdditionalTrySearches
    }
    predicted {
      predictedCompany
      predictedContact
      searchedCompany
      searchedContact
      searchId
    }
    timedout {
      company
      contact
    }
  }
}
"}
